import argparse
from kafka.admin import AdminClient, NewTopic

def create_topic(topic_name, num_partitions, replication_factor):
    admin_client = AdminClient({'bootstrap.servers': 'your_kafka_broker_address'})
    new_topics = [NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor)]
    results = admin_client.create_topics(new_topics)
    
    for topic, future in results.items():
        try:
            future.result()
            print(f"Topic {topic} created successfully.")
        except Exception as e:
            print(f"Failed to create topic {topic}: {e}")

def main():
    parser = argparse.ArgumentParser(description='Kafka cluster administration script.')
    parser.add_argument('topic_name', type=str, help='Name of the topic to create')
    parser.add_argument('--partitions', type=int, default=1, help='Number of partitions (default: 1)')
    parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor (default: 1)')

    args = parser.parse_args()
    create_topic(args.topic_name, args.partitions, args.replication_factor)

if __name__ == "__main__":
    main()